class Solution {
public:
    int trap(vector<int>& height) {
        int n = height.size();
        int water = 0;
        int elev = 0;

        for(int l = 0, r = n-1; l != r;){
            int temp;

            elev = max(elev , min(height[l], height[r]));

            if(height[l] < height[r]){
                temp = l;
                l++;
            } else{
                temp = r;
                r--;
            }

            water += elev - height[temp];

        }

        return water;

    }
};
